queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?activity_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasActivities ?child ; p:hasHealth_Promotion_Program ?parent . } GROUP BY ?child }
  ?child p:activity_name ?activity_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Health_Promotion_Program } }
  FILTER(?nf = ?total)
}

